ansparency focus"]$json$::jsonb, $json$["poor service response","billing/levy disputes","deposit refunds"]$json$::jsonb, $json${"summary":"Limited recent X activity; HelloPeter mixed-negative recent; historical service awards.","positive_themes":["experience","personal service","transparency","dedicated teams"],"common_concerns":["billing disputes","poor service response","deposit issues"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
