al network","PPRA compliance","full-service rental management","market insights via blog"]$json$::jsonb, $json$["deposit withholding","maintenance neglect","agent unprofessionalism"]$json$::jsonb, $json${"summary":"Predominantly negative from HelloPeter/Google reviews (deposits, service); neutral/positive company news/blogs.","positive_themes":["professional service in some cases","market knowledge","transformation efforts"],"common_concerns":["deposit disputes","poor maintenance response","unprofessional agents","communication delays"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
