sonb, $json$["unresponsive service","deposit handling","tenant vetting failures"]$json$::jsonb, $json${"summary":"HelloPeter overwhelmingly negative (1.9/5); isolated FB complaints; sparse positive employee reviews.","positive_themes":["none prominent"],"common_concerns":["poor communication","deposit disputes","bad tenant placement","unresponsive accounts"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
