","ios":"N/A"}$json$::jsonb, $json$["20+ years experience","large agent network (450+ pros)","multi-province coverage","positive employee culture","market insights/news"]$json$::jsonb, $json$["unresponsive support","maintenance delays","unclean rentals"]$json$::jsonb, $json${"summary":"HelloPeter strongly negative on lettings (filthy properties, no support); no recent positive customer data; employee reviews 4.2/5 Indeed.","positive_themes":["efficient sales agents (rare)","good office culture"],"common_concerns":["poor maintenance","unclean properties","unresponsive service","hidden costs","delayed move-ins"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
