ustomer loyalty program"]$json$::jsonb, $json$["Trustpilot low 1.7/5","product quality issues","return processing delays"]$json$::jsonb, $json${"summary":"App rated 4.7/4.4; Trustpilot 1.7/5; mixed on product quality; positive for deals/convenience.","positive_themes":["deals/discounts","easy returns","wide selection","fast delivery"],"common_concerns":["low quality items","delayed refunds","inconsistent service"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
