INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('profmed-medical-aid', 'Profmed Medical Aid', 'medical-aid', 71, 'GO WITH CAUTION', 'https://rehealth.co.za/wp-content/uploads/2022/02/profmed_medicalaid.png', 'https://www.profmed.co.za', $json$[{"category":"Compliance","score":"18/20","description":"CMS registered medical scheme, AA- GCR rating for financial strength, governed per Medical Schemes Act & King IV, no major sanctions 2025/2026."},{"category":"Customer Satisfaction","score":"12/20","description":"HelloPeter 1.52/5 overall (23 recent reviews), TrustIndex 2.8; mostly 1-star recent reviews."},{"category":"Product Value","score":"28/30","description":"Competitive pricing with good range (10 plans), low increases, unlimited hospital/PMB; day-to-day varies by plan."},{"category":"Innovation","score":"7/10","description":"Profmed app (claims, ER locator, baby program), Amplifire wellness booster, digital assessments; app criticized for poor quality."},{"category":"Customer Support","score":"9/15","description":"Phone/chat/app channels; frequent complaints of unresponsiveness, delays despite promises; some positive testimonials."},{"category":"Accessibility & Security","score":"8/10","description":"Digital app available but glitchy; no security breaches found; regulated under Medical Schemes Act implies POPIA compliance."}]$json$::jsonb, $json$["unlimited hospital cover","PMB+chronic","day-to-day benefits (higher plans)","maternity programs","international travel assistance","network options for affordability"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: From R1,022/mo (ProSelect Savvy) to R13,309 (ProPinnacle); 2026 +6.76%","features":""}]$json$::jsonb, $json${"google_play":"N/A (few reviews, negative feedback)","ios":"~2/5 (based on negative App Store reviews)"}$json$::jsonb, $json$["affordable increases (6.76% 2026)","strong finances (AA GCR)","tailored for professionals","comprehensive oncology/maternity"]$json$::jsonb, $json$["poor service responsiveness","claims issues","app functionality"]$json$::jsonb, $json${"summary":"HelloPeter strongly negative recent; some positive Reddit/FB; no strong X data.","positive_themes":["efficient claims (some)","good major procedure cover","value for money"],"common_concerns":["unresponsive support","claims delays/denials","app glitches"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('discovery-health-medical-scheme', 'Discovery Health Medical Scheme', 'medical-aid', 70, 'GO WITH CAUTION', 'https://seeklogo.com/images/D/discovery-health-logo-1DFC1C6E6D-seeklogo.com.png', 'https://www.discovery.co.za/medical-aid', $json$[{"category":"Compliance","score":"18/20","description":"CMS registered #1125, strong solvency >30%, no major recent penalties (past prepaid issue 2020). CMS overseeing 2026 pharmacy recovery."},{"category":"Customer Satisfaction","score":"8/25","description":"HelloPeter 1.25/5 (1,514 recent reviews, 90% 1-star), mixed Reddit. Backlash on pharmacy error recoveries."},{"category":"Product Value","score":"28/35","description":"25 plans R1,278-R12,338/mo, 2026 increases 0-7.9% deferred Apr, strong hospital/chronic value in-network."},{"category":"Innovation","score":"9/10","description":"AI Personal Health Pathways/fund (up to R12k), virtual GP, symptom checker, Smart Saver plans."},{"category":"Customer Support","score":"9/15","description":"0860 lines, app claims, 100% HelloPeter response (avg 13h), but complaints on delays/rudeness."},{"category":"Accessibility & Security","score":"9/10","description":"Modern app with digital claims, POPIA-compliant manual published, inclusive plans for families. No breaches noted."}]$json$::jsonb, $json$["Unlimited network hospital","Personal Health Fund","PMB/chronic cover","maternity programme","screenings","virtual care"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: From R1,278/mo KeyCare Start Regional; Active Smart R1,350 unchanged 2026","features":""}]$json$::jsonb, $json${"google_play":"4.2/5","ios":"New app, mixed early reviews"}$json$::jsonb, $json$["Market leader 58%","innovative AI tools","AAA financials","150+ hospitals network","comprehensive benefits"]$json$::jsonb, $json$["claims disputes","poor service ratings","billing issues","2026 pharmacy recovery demands"]$json$::jsonb, $json${"summary":"Low HelloPeter (1.25/5), Reddit mixed (good majors/poor admin), news positive innovation but pharmacy backlash.","positive_themes":["major claims paid","tech innovation","affordability deferrals","network access"],"common_concerns":["claims rejections/delays","billing errors","poor customer service","network restrictions"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
